import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Product } from '../types';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faFacebook, faInstagram, faYoutube, faBlogger, faTwitter, faTelegram } from '@fortawesome/free-brands-svg-icons';

const categoryIcon = {
  '페이스북': { icon: faFacebook, color: 'text-blue-600' },
  '인스타그램': { icon: faInstagram, color: 'text-pink-500' },
  '유튜브': { icon: faYoutube, color: 'text-red-600' },
  '블로그': { icon: faBlogger, color: 'text-orange-500' },
  '트위터': { icon: faTwitter, color: 'text-sky-400' },
  '텔레그램': { icon: faTelegram, color: 'text-blue-400' },
  '기타': { icon: faBlogger, color: 'text-gray-400' },
};

const Home: React.FC = () => {
  const [recentProducts, setRecentProducts] = useState<Product[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string>('전체');
  const [slideIndex, setSlideIndex] = useState(0);

  const categories: string[] = ['전체', '페이스북', '인스타그램', '유튜브', '블로그', '트위터', '텔레그램', '기타'];

  // Mock data for popular products
  const popularProducts: Product[] = [
    { id: 1, name: '페이스북 팔로워 1000명', price: '50,000원', category: '페이스북', image: 'facebook.png' },
    { id: 2, name: '인스타그램 팔로워 500명', price: '30,000원', category: '인스타그램', image: 'instagram.png' },
    { id: 3, name: '유튜브 구독자 1000명', price: '100,000원', category: '유튜브', image: 'youtube.png' },
    { id: 4, name: '블로그 방문자 5000명', price: '80,000원', category: '블로그', image: 'blog.png' },
    { id: 5, name: '트위터 팔로워 300명', price: '20,000원', category: '트위터', image: 'twitter.png' },
    { id: 6, name: '텔레그램 멤버 200명', price: '15,000원', category: '텔레그램', image: 'telegram.png' },
    { id: 7, name: '페이스북 좋아요 2000개', price: '40,000원', category: '페이스북', image: 'facebook.png' },
    { id: 8, name: '인스타그램 좋아요 1000개', price: '25,000원', category: '인스타그램', image: 'instagram.png' },
    { id: 9, name: '유튜브 조회수 10000회', price: '60,000원', category: '유튜브', image: 'youtube.png' },
    { id: 10, name: '블로그 댓글 100개', price: '35,000원', category: '블로그', image: 'blog.png' },
    { id: 11, name: '트위터 리트윗 500개', price: '45,000원', category: '트위터', image: 'twitter.png' },
    { id: 12, name: '텔레그램 뷰 1000회', price: '30,000원', category: '텔레그램', image: 'telegram.png' },
  ];

  const filteredProducts: Product[] = selectedCategory === '전체' 
    ? popularProducts 
    : popularProducts.filter(product => product.category === selectedCategory);

  // 슬라이드 관련
  const getSlidesToShow = () => {
    if (window.innerWidth < 640) return 1;
    if (window.innerWidth < 1024) return 2;
    return 4;
  };
  const [slidesToShow, setSlidesToShow] = useState(getSlidesToShow());

  React.useEffect(() => {
    const handleResize = () => setSlidesToShow(getSlidesToShow());
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const maxIndex = Math.max(0, popularProducts.length - slidesToShow);
  const handlePrev = () => setSlideIndex(idx => Math.max(0, idx - 1));
  const handleNext = () => setSlideIndex(idx => Math.min(maxIndex, idx + 1));

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <div className="bg-gradient-to-r from-blue-600 to-blue-800 text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-4xl md:text-6xl font-bold mb-6">
            소셜미디어 마케팅의 새로운 기준
          </h1>
          <p className="text-xl md:text-2xl mb-8 text-blue-100">
            애드모어와 함께 당신의 소셜미디어를 성장시키세요
          </p>
          <Link
            to="/products"
            className="bg-white text-blue-600 px-8 py-3 rounded-lg text-lg font-semibold hover:bg-gray-100 transition duration-300"
          >
            상품 보기
          </Link>
        </div>
      </div>

      {/* Popular Products Section - 슬라이드 */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <h2 className="text-3xl font-bold text-gray-900 mb-8">인기 상품</h2>
        <div className="relative">
          <button
            className="absolute left-0 top-1/2 -translate-y-1/2 z-10 bg-white border rounded-full w-10 h-10 flex items-center justify-center shadow hover:bg-gray-100"
            onClick={handlePrev}
            disabled={slideIndex === 0}
            aria-label="이전"
          >
            &#60;
          </button>
          <div className="overflow-hidden">
            <div
              className="flex transition-transform duration-500"
              style={{ transform: `translateX(-${(100 / slidesToShow) * slideIndex}%)` }}
            >
              {popularProducts.slice(slideIndex, slideIndex + slidesToShow).map((product) => (
                <div key={product.id} className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition duration-300 mx-2 min-w-0 flex-1">
                  <div className="flex justify-center items-center h-48 bg-gray-50">
                    <FontAwesomeIcon
                      icon={categoryIcon[product.category]?.icon}
                      className={`text-6xl ${categoryIcon[product.category]?.color}`}
                    />
                  </div>
                  <div className="p-4">
                    <h3 className="font-semibold text-gray-900 mb-2">{product.name}</h3>
                    <p className="text-blue-600 font-bold">{product.price}</p>
                    <button className="mt-3 w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition duration-300">
                      구매하기
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
          <button
            className="absolute right-0 top-1/2 -translate-y-1/2 z-10 bg-white border rounded-full w-10 h-10 flex items-center justify-center shadow hover:bg-gray-100"
            onClick={handleNext}
            disabled={slideIndex === maxIndex}
            aria-label="다음"
          >
            &#62;
          </button>
        </div>
      </div>

      {/* Category Filter */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex flex-wrap gap-2 mb-8">
          {categories.map((category) => (
            <button
              key={category}
              onClick={() => setSelectedCategory(category)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition duration-300 ${
                selectedCategory === category
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              {category}
            </button>
          ))}
        </div>
      </div>

      {/* All Products Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
